var e=[{id:`L2_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`흐아암.`,JPN:`ふぁあ。`,ENG:`*Yawn*`,TWN:`哈啊啊。`},stage:{bg:`CAFE_STREGA`,slots:{L:{char_id:`CAT_STREGA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L3_1`,type:`dialog`,speaker:`CAT_STREGA_NULL_NULL`,text:{KOREA:`냐옹!`,JPN:`にゃあ！`,ENG:`Meow!`,TWN:`喵！`},stage:{bg:`CAFE_STREGA`,slots:{L:{char_id:`CAT_STREGA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L4_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`플루토, 좋은 아침……. `,JPN:`プルートー、おはよう。`,ENG:`Pluto, good morning... `,TWN:`布魯托，早安……`},stage:{bg:`CAFE_STREGA`,slots:{L:{char_id:`CAT_STREGA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L5_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`어?`,JPN:`あれ？`,ENG:`Huh?`,TWN:`嗯？`},stage:{bg:`CAFE_STREGA`,slots:{L:{char_id:`CAT_STREGA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L9_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`……에블린 언니?`,JPN:`……エヴリンお姉さん？`,ENG:`Evelyn?`,TWN:`……伊芙琳姊姊？`},stage:{bg:`CAFE_STREGA`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`오늘 카페 쉬는 날인데……. 이렇게 일찍 어디 가는 거지?`,JPN:`今日はカフェの定休日だよね……こんな朝早くからどこに行くんだろ？`,ENG:`The shop’s closed today... Where is she going?`,TWN:`今天咖啡廳不是休息嗎……她一大早去哪？`},stage:{bg:`CAFE_STREGA`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`어쩌면 정식 마녀가 되는 비결을 알 수 있을지도 몰라!`,JPN:`もしかしたら正式な魔女になる方法がわかるかも知れない！`,ENG:`Maybe she’s going to do something that real witches do!`,TWN:`說不定能學到成為正式魔女的秘訣！`},stage:{bg:`CAFE_STREGA`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`몰래 따라가야겠다!!`,JPN:`こっそりついて行こう！！`,ENG:`I’ll secretly follow her!`,TWN:`我要偷偷跟上！！`},stage:{bg:`CAFE_STREGA`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`CAT_STREGA_NULL_NULL`,text:{KOREA:`냐오옹~`,JPN:`にゃ～。`,ENG:`Meow!`,TWN:`喵～`},stage:{bg:`CAFE_STREGA`,slots:{L:null,C:{char_id:`CAT_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`쉿. 알았어. 데려갈 테니까 조용히 해야 해?`,JPN:`しっ。わかったから。連れて行くから静かにしてね？`,ENG:`Shush. You can come with me. But don’t make a sound, okay?`,TWN:`噓，我會帶著你的，但你要安靜喔，知道嗎？`},stage:{bg:`CAFE_STREGA`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`앗, 골목으로 사라진다! 얼른 따라가자!`,JPN:`あっ、路地に入った！　早く行こう！`,ENG:`Oh, she’s going into an alley! Hurry, let’s go!`,TWN:`啊，消失在巷子裡了！快跟上！`},stage:{bg:`CAFE_STREGA`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`EVELYN_STREGA_NULL_NULL`,text:{KOREA:`저 왔어요~`,JPN:`おはようございます～！`,ENG:`I’m here.`,TWN:`我來了～`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`EVELYN_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`VENDOR_EXTRA_NULL_MARKET`,text:{KOREA:`오, 켈러 씨! 싱싱한 열대 과일이 들어왔는데 사 갈 거지?`,JPN:`おお、ケラーさん！　新鮮なトロピカルフルーツが入ったけど、買って行くかい？`,ENG:`Oh, Ms. Keller! We have some nice fresh fruit. Do you want some?`,TWN:`噢，是凱樂！我們新進了一些熱帶水果，要買嗎？`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`EVELYN_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`EVELYN_STREGA_NULL_NULL`,text:{KOREA:`당연하죠. 마침 계절 메뉴로 과일 샤베트도 생각하고 있었는데.`,JPN:`もちろんです。季節メニューでフルーツシャーベットを考えていたので、ちょうど良かったです。`,ENG:`Of course. I was actually thinking of adding fruit sherbet to our seasonal menu.`,TWN:`當然好，正好考慮要不要推出當季的果汁呢。`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`EVELYN_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`EVELYN_STREGA_NULL_NULL`,text:{KOREA:`나중에 카페 놀러오세요. 아저씨한테는 무료로 대접해 드릴 테니까♪`,JPN:`今度、カフェにいらしてください。おじさんにはただで御馳走しますから♪`,ENG:`Come visit my cafe when you have the time. It will be my treat. ♪`,TWN:`歡迎下次來咖啡廳玩，可以請大叔免費喝一杯♪`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`EVELYN_STREGA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`VENDOR_EXTRA_NULL_MARKET`,text:{KOREA:`하하. 좋았어. 그럴 줄 알고 내가 최상급으로만 모아뒀지.`,JPN:`ハハ。ありがとう。そう言うと思って、最上級のものだけ持ってきたんだよ。`,ENG:`Haha, sure. Here, I have the best fruit reserved for you.`,TWN:`哈哈。謝謝。我就知道你會這麼說，所以特地留了品質最好的要給你。`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`EVELYN_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};